from sqlalchemy import text

from ..db.session import PostgresSession

class PostgresLoader:
    def __init__(self, query: str):
        self.query = query

    def load(self) -> list[dict]:
        with PostgresSession() as session:
            result = session.execute(text(self.query))
            columns = result.keys()
            return [dict(zip(columns, row)) for row in result.fetchall()]

from pathlib import Path

class QueryLoader():
    BASE_DIR = Path(__file__).resolve().parent / "queries"

    @classmethod
    def load(cls, name: str) -> str:
        path = cls.BASE_DIR / f"{name}.sql"
        if not path.is_file():
            raise FileNotFoundError(f"Query {name} não encontrada em {path}")
        return path.read_text(encoding="utf-8")

#Produto repository: classe responsável por acessar os dados dos produtos no banco de dados cache
#Repository com sessão interna porque não sei fazer com sessão externa
from contextlib import contextmanager
from typing import List, Dict, Optional
from sqlalchemy import insert, select
from db.session import SqliteSession
from models.produto import Produto
from utils.codigo import Codigo


class ProdutoRepository:
    def __init__(self) -> None:
        pass

    @contextmanager
    def _session_scope(self):
        # Encapsula e gerencia a sessão do banco de dados
        session = SqliteSession()
        try:
            yield session
            session.commit()
        except:
            session.rollback()
            raise
        finally:
            session.close()

    def deletar_todos(self) -> None:
        with self._session_scope() as session:
            session.query(Produto).delete()

    def salvar_lote(self, produtos: List[Dict]):
        with self._session_scope() as session:
            session.execute(insert(Produto), produtos)

    def listar(self) -> List[Produto]:
        with self._session_scope() as session:
            return session.query(Produto).all()

    def obter_por_codigo(self, codigo: str) -> Optional[Produto]:
        codigo_valor = Codigo(codigo).valor
        with self._session_scope() as session:
            stmt = select(Produto).where(Produto.codigo == codigo_valor)
            return session.execute(stmt).scalars().first()

import json
from datetime import datetime
from pathlib import Path
from typing import Dict, List

IGNORE_DIRS = {".git", ".venv", "venv", "__pycache__", "output", ".md", "__init__.py", "planilhas", ".uv-cache",".vscode"}


def is_ignored(path: Path) -> bool:
    return any(part in IGNORE_DIRS for part in path.parts)


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8", errors="ignore")


def to_module_name(rel_path: str) -> str:
    module = rel_path.replace("/", ".").removesuffix(".py")
    if module.endswith(".__init__"):
        module = module[: -len(".__init__")]
    return module


def collect_source_files(root: Path) -> List[Dict[str, str]]:
    files: List[Dict[str, str]] = []
    for p in sorted(root.rglob("*")):
        if p.is_file() and not is_ignored(p):
            if p.suffix not in {".py", ".sql"}:
                continue
            rel = p.relative_to(root).as_posix()
            entry: Dict[str, str] = {
                "path": rel,
                "content": read_text(p),
            }
            if p.suffix == ".py":
                entry["module"] = to_module_name(rel)
            files.append(entry)
    return files


def build_index(files: List[Dict[str, str]]) -> List[str]:
    return [f["path"] for f in files]


def build_top_level(files: List[Dict[str, str]]) -> Dict[str, List[str]]:
    dirs = set()
    root_files = set()
    for f in files:
        path = f["path"]
        if "/" in path:
            dirs.add(path.split("/", 1)[0])
        else:
            root_files.add(path)
    return {
        "dirs": sorted(dirs),
        "files": sorted(root_files),
    }


def build_dump(root: Path) -> Dict[str, object]:
    files = collect_source_files(root)
    return {
        "schema_version": "1.2",
        "generated_at": datetime.now().isoformat(timespec="seconds"),
        "root": root.name,
        "description": "Dump do source code Python (.py) e SQL (.sql) com paths relativos.",
        "context": {
            "notes": [
                "Arquivos que nao sao .py ou .sql foram excluidos.",
                "Caminhos sao relativos a raiz do projeto.",
                "O campo module existe apenas para arquivos .py.",
            ]
        },
        "summary": {
            "file_count": len(files),
        },
        "layout": {
            "top_level": build_top_level(files),
        },
        "file_index": build_index(files),
        "files": files,
    }


def main() -> None:
    today = datetime.now().strftime("%Y.%m.%d")
    base = Path(__file__).parents[1]
    dump = build_dump(base)
    out_file = base / f"dump_{today}.json"
    out_file.write_text(
        json.dumps(dump, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )
    size_kb = out_file.stat().st_size // 1024
    print(f"Arquivo criado: {out_file} ({size_kb} KB)")


if __name__ == "__main__":
    main()

import re
from typing import Optional


class Codigo:
    def __init__(self, valor: str) -> None:
        if not isinstance(valor, str):
            raise TypeError("Codigo deve ser uma string")
        normalizado = self.normalizar(valor)
        if not self.validar(normalizado):
            raise ValueError(f"Codigo invalido: {valor!r}")
        self._valor = normalizado
        self._tipo = self.detectar_tipo(normalizado)

    @property
    def valor(self) -> str:
        return self._valor

    @property
    def tipo(self) -> Optional[str]:
        return self._tipo

    @staticmethod
    def normalizar(codigo: str) -> str:
        codigo = codigo.strip()
        return re.sub(r"[\s-]", "", codigo)

    @classmethod
    def validar(cls, codigo: str) -> bool:
        return cls.detectar_tipo(codigo) is not None

    @classmethod
    def detectar_tipo(cls, codigo: str) -> Optional[str]:
        if cls.is_ean13(codigo):
            return "EAN13"
        if cls.is_ean12(codigo):
            return "EAN12"
        if cls.is_ean8(codigo):
            return "EAN8"
        if cls.is_plu6(codigo):
            return "PLU6"
        return None

    @classmethod
    def is_ean13(cls, codigo: str) -> bool:
        return cls._validar_ean(codigo, 13)

    @classmethod
    def is_ean12(cls, codigo: str) -> bool:
        return cls._validar_ean(codigo, 12)

    @classmethod
    def is_ean8(cls, codigo: str) -> bool:
        return cls._validar_ean(codigo, 8)

    @staticmethod
    def is_plu6(codigo: str) -> bool:
        return codigo.isdigit() and len(codigo) == 6

    @staticmethod
    def _validar_ean(codigo: str, tamanho: int) -> bool:
        if len(codigo) != tamanho or not codigo.isdigit():
            return False
        corpo = codigo[:-1]
        digito = int(codigo[-1])
        soma = 0
        peso = 3
        for ch in reversed(corpo):
            soma += int(ch) * peso
            peso = 1 if peso == 3 else 3
        calculado = (10 - (soma % 10)) % 10
        return calculado == digito
